export interface MsgDecodeError {
  type: "decode_error";
  sessionId: string;
  code: string;
  message: string;
  partialPixels?: ArrayBuffer;       // transferred; present for TruncatedStream
  partialInfo?: ImageInfo;
  partialPixelStride?: number;       // bytes per row; required when partialPixels is present
  partialStage?: DecodeStage;        // stage at which the error occurred
}

// In MsgEncodeStart (protocol.ts) — missing fields:
// modular, brotliEffort, decodingSpeed, photonNoiseIso,
// jpegReconstruction, alreadyDownsampled, upsamplingMode,
// ecResampling, frameIndexing, allowExpertOptions, buffering

// EncodeOptions has all of these but encode-session.ts never copies them:
if (opts.progressiveDc != null) (startMsg as any).progressiveDc = opts.progressiveDc;
if (opts.groupOrder != null) (startMsg as any).groupOrder = opts.groupOrder;
// ... no handling for the fields listed above

export interface EncodeSession {
  readonly id: string;
  pushPixels(chunk: ArrayBuffer, region?: Region): Promise<void>;
  finish(): Promise<void>;
  chunks(): AsyncIterable<ArrayBuffer>;
  done(): Promise<number>;
  // Available after done() resolves. Null before completion or on error.
  getStats(): EncodeStats | null;
  cancel(reason?: string): Promise<void>;
}

export interface EncodeStats {
  /** Raw pixel bytes: width × height × channels × bytesPerChannel. */
  originalBytes: number;
  /** Total JXL bytes written across all chunks (including sidecars). */
  compressedBytes: number;
  /** compressedBytes / originalBytes. Values below 1.0 indicate net compression. */
  ratio: number;
  sidecarOffsets?: readonly number[];
}

export interface DecodeSession {
  readonly id: string;
  // Stream the bytes in; resolves when worker has accepted the chunk
  push(chunk: ArrayBuffer | Uint8Array): Promise<void>;
  // Signal end of input
  close(): Promise<void>;
  // Iterate frames as they emit
  frames(): AsyncIterable<DecodeFrameEvent>;
  // Await final completion; rejects on error or abort
  done(): Promise<ImageInfo>;
  // Cancel and release codec resources
  cancel(reason?: string): Promise<void>;
}
